// AUTO-GENERATED by scripts/build-seed.mjs — do not edit by hand.
import type { Activity } from "@/lib/types";

export const ogActivities: Activity[] = [
  {"id":"og-jailbreak-flag-raid","title":"Jailbreak Flag Raid","altNames":["Prison Break CTF","Three-Flag Raid","Jailbreak Capture"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":12,"groupMax":30,"energy":3,"prep":"Low","blurb":"A capture-the-flag where springing your jailed teammates is as valuable as stealing the flag.","materials":["6 cones to mark territory line and two jails","2 team identifiers such as bandanas or pinnies, one color per team","3 cloth flags or rag scraps per team (place at different depths)","1 whistle"],"materialTags":["Cones","Team identifiers","Flags or pinnies","Whistle"],"steps":["Split the field down the middle with a cone line; give each team a jail box (4 cones) deep in their own half and stake their three flags at shallow, medium, and deep positions.","On your half you are safe; the moment you cross the center line into enemy ground you can be tagged.","A tagged raider walks to the enemy jail and waits there with one hand out.","A teammate who sneaks in and slaps a jailed hand frees every prisoner in that jail; freed players get a free walk back across the line, hands up, untaggable.","Carry any enemy flag across the center line to bank one point; a team scores again only after all its banked raiders are home.","Blow the whistle to pause and re-balance if one team is pinned; play to a flag total or a time cap, then swap sides."],"notes":"Best with two counselors, one roaming each half to call tags. Rotate a 'jail guard' rule on and off: allowing one guard per jail tightens the game, banning guards opens it up and rewards bold rescues. To scale up for grades 7-12, shrink the safe zone, require raiders to physically tag the jail wall (a cone) not just a hand, and add a third deep flag worth double.","safety":"Two-finger touches only, no grabbing pinnies off bodies or tackling. Set boundary cones a full body-length away from any fence, slope, or goalpost since sprinting raiders watch the flag, not their feet.","ages":["g46","g79","g1012"],"rating":5,"media":[{"title":"Video demos: Jailbreak Flag Raid","url":"https://www.youtube.com/results?search_query=jailbreak+capture+the+flag+camp+game+with+jail+rescue"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Jailbreak Flag Raid","url":"https://www.google.com/search?q=jailbreak+capture+the+flag+jail+rescue+variant"}],"variations":["Hospital tag: instead of jail, a tagged player kneels where they were caught and a teammate's two-hand touch revives them, keeping the action spread across the field.","Medic rule: each team secretly picks one 'medic' whose touch is the only way to free a jail, so teams must protect and disguise their key player.","For grades 7-12, add a 'no-fly zone' band on each side of the center line where flag carriers may not stop or pass, forcing committed sprints and harder defensive reads.","Glow-flag dusk version stays daytime-safe by using brightly colored rags and a shortened field so spotting flags is the strategic puzzle."],"subsets":[["Walk the center line first so every camper can see exactly where 'safe' ends.","Stake the deep flag far enough back that a clean steal takes teamwork, not one fast kid."],[],["Show that jailed players form a chain, hand-to-hand, so one rescue can free a whole line."],["Demo the free walk-back with hands raised so taggers know to leave freed players alone."],[],[]]},
  {"id":"og-blob-tag-amoeba","title":"Blob Tag (Amoeba)","altNames":["Amoeba Tag","Chain Tag","Blob Monster"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":8,"groupMax":24,"energy":3,"prep":"None","blurb":"One tagger becomes two, then four, then a hand-linked blob that swallows the whole field.","materials":["6-8 cones to mark a shrinking rectangle"],"materialTags":["Cones"],"steps":["Cone off a rectangle and send everyone inside; pick one camper to start as the blob.","The blob chases and tags runners; each tagged runner joins hands with the blob.","Only the two players on the ends of the blob's chain have free 'tagging hands' — the middle players must hold on.","When the blob reaches four players it must split into two separate blobs of two, which now hunt independently.","Keep splitting at every four; the last untagged runner wins and starts the next round as the first blob.","Shrink the rectangle by moving cones in once half the group is caught, squeezing the survivors together."],"notes":"The split-at-four rule is what keeps a big group fast and fair; without it the blob becomes one slow clump. Younger grade-4 groups can skip splitting and just grow one giant blob. For grades 7-9, require the blob to fully encircle a runner (close the chain around them) rather than tag, turning it into a coordination and communication challenge.","safety":"Blobs may not 'crack the whip' by swinging the end players; everyone moves at the pace of their slowest linked member. Drop linked hands immediately if anyone stumbles, and keep the zone clear of poles and curbs.","ages":["g46","g79"],"rating":4,"media":[{"title":"Video demos: Blob Tag","url":"https://www.youtube.com/results?search_query=blob+tag+amoeba+tag+camp+game+rules"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: Blob Tag","url":"https://www.google.com/search?q=blob+tag+amoeba+tag+splitting+rules"}],"variations":["No-split mega-blob: one ever-growing chain hunts the last runners, best for younger or smaller groups who want simple chaos.","Encircle-to-catch: the blob must surround and close a circle around a runner instead of tagging, demanding teamwork for grades 7-9.","Two-blob start: begin with two separate blobs racing to absorb the field first, adding a competitive edge for older campers.","Frozen-blob twist: if a blob lets go of hands mid-chase, it must freeze and re-link before continuing, punishing sloppy coordination."],"subsets":[[],["Stress that tagged runners join at the END of the chain, never the middle."],[],["Pre-assign who breaks off when the count hits four so splits are clean and fast.","Have the new pairs raise free hands so everyone sees who can tag."],[],[]]},
  {"id":"og-steal-the-bacon-numbers","title":"Steal the Bacon Showdown","altNames":["Steal the Bacon","Number Grab","Bacon Snatch"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":10,"groupMax":24,"energy":3,"prep":"Low","blurb":"Two teams, one object in the middle, and a number called — grab and dash before your rival tags you.","materials":["1 'bacon' object such as a beanbag, pinnie, or playground ball","4 cones for two team lines and the centerline","Sidewalk chalk to number positions"],"materialTags":["Beanbag","Cones","Sidewalk chalk"],"steps":["Form two equal lines facing each other about 30 feet apart; place the bacon on a center spot between them.","Number off each team from opposite ends so every player has a matching opponent across the field.","Call a number; both players with that number sprint to the center.","Snatch the bacon and race it back across your own line to score one point — but if your opponent tags you while you hold it, they score instead.","If neither dares grab, players may fake and feint; the bacon must be carried, not thrown.","Call numbers in any order, sometimes calling two at once to send four runners; first team to ten points wins."],"notes":"The standoff at the center is the whole game — coach campers to bait the grab and dodge. Number off from opposite ends so an even matchup faces off, not the two fastest kids. To scale up for grades 7-9, call multiple numbers so pairs must decide who grabs and who blocks, and add a rule that a dropped bacon is live for anyone whose number was called.","safety":"Tags are open-hand touches to the back or shoulder, never shoves into the chest. Keep the two waiting lines seated or kneeling so no one drifts into the sprint lane.","ages":["g46","g79"],"rating":4,"media":[{"title":"Video demos: Steal the Bacon","url":"https://www.youtube.com/results?search_query=steal+the+bacon+camp+game+how+to+play"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Steal the Bacon","url":"https://www.google.com/search?q=steal+the+bacon+game+variations"}],"variations":["Tag-back rule: a runner who grabs the bacon can be tagged on the way home, turning every snatch into a risk-reward gamble.","Double-call sends two numbers per team at once, forcing 2-on-2 strategy over who grabs and who screens for grades 7-9.","Math-call version: instead of a number, shout a problem ('seven plus two!') and the players whose number is the answer run, sneaking in mental math.","Three-team triangle places three lines around a center bacon, so reading two opponents at once raises the strategy ceiling."],"subsets":[["Pace off 30 feet and drop the center spot exactly midway so neither side has an edge."],["Number from opposite ends: team A counts left-to-right, team B right-to-left."],[],["Walk through a slow-motion grab-and-tag so the 'tagged while holding' rule is crystal clear."],[],[]]},
  {"id":"og-pin-kickball","title":"Pin Kickball","altNames":["Bottle Kickball","Cone Kickball","Kickball Defense"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":12,"groupMax":24,"energy":3,"prep":"Low","blurb":"Kickball with a twist — the fielders can't tag you out, they have to knock over a pin first.","materials":["1 playground ball to kick","4 cones or bases for the diamond","3 cones or stacked cups as knock-down 'pins' at each base"],"materialTags":["Playground balls","Cones"],"steps":["Set a four-base diamond and stand a knock-down pin (a cone or a stack of cups) just beside each base.","The kicking team rolls a pitch and kicks like normal kickball, then runs the bases.","Fielders can't tag runners; to make an out they must field the ball and topple the pin at the base the runner is heading for before the runner arrives.","A runner who beats the pin-knock is safe; a runner caught between toppled pins is out.","Three outs flips the teams; fielders re-stand every pin between batters.","Count a run each time a kicker rounds all four bases home; play set innings and total the runs."],"notes":"The pin rule rewards accurate throwing and quick relays over raw speed, which levels the field for mixed athletic groups. Station your strongest throwers won't dominate because every out needs a clean hit on a small target. For grades 10-12, add force-out logic at every base and require a two-pass relay (no single player may field and knock the same pin) to make defense a true team puzzle.","safety":"Throws aim at the pins on the ground, never at runners' bodies or heads. Keep pins a stride away from the base itself so runners and the toppling pin don't collide.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Video demos: Pin Kickball","url":"https://www.youtube.com/results?search_query=kickball+variation+knock+down+pin+camp+game"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Pin Kickball","url":"https://www.google.com/search?q=kickball+variations+camp+pin+knockdown"}],"variations":["Big-base chaos: allow multiple runners on one base so the kicking team can stack pressure and the defense must choose which runner to stop.","No-pitch tee version sets the ball on a cone so weaker kickers still launch it and the focus stays on baserunning strategy.","Two-relay rule for grades 10-12 forces the ball through two different fielders before any pin can be knocked, demanding real teamwork.","Pin-jackpot: knocking the home pin while a runner is mid-base ends the whole inning instantly, a high-risk defensive gamble."],"subsets":[["Space the diamond bases about 45 feet apart for grade-4 to 6; widen for older kickers."],[],["Demo a slow relay-and-knock so kickers see the timing window they're racing."],[],[],[]]},
  {"id":"og-ultimate-lite-endzone","title":"Endzone Ultimate-Lite","altNames":["Ultimate Frisbee Lite","Endzone Disc","No-Contact Ultimate"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":10,"groupMax":20,"energy":3,"prep":"Low","blurb":"Pass a disc downfield without ever running with it — catch it in the endzone to score.","materials":["1 flying disc (or a foam ball if no disc)","8 cones to mark two endzones and sidelines","2 sets of team identifiers"],"materialTags":["Cones","Team identifiers"],"steps":["Cone a long rectangle with an endzone at each end and split into two even teams.","Start each point with one team throwing the disc from their endzone to the other team (a 'pull').","Whoever has the disc must stop moving and throw within five seconds; you can never run while holding it.","Teammates cut and get open; complete passes move the disc downfield toward the opposing endzone.","An incomplete, dropped, or intercepted pass turns the disc over to the other team right where it landed.","Catch the disc inside the opponent's endzone to score a point, then re-pull from the scoring team; play to a point total or time cap."],"notes":"Teach the five-second stall count out loud — it's what keeps the game flowing and stops one camper hogging the disc. Mixed groups thrive because cutting and throwing matter more than raw speed. For grades 10-12, add the real rule that the marker counts 'stalling one, two…' to ten and play 'spirit of the game' self-officiating where players make their own calls, building sportsmanship and pressure-handling.","safety":"No contact at all — no bumping a cutter, blocking with the body, or diving into another player; play the disc, not the person. Call your own collisions and stop play immediately if a disc is heading toward someone's face.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Video demos: Endzone Ultimate-Lite","url":"https://www.youtube.com/results?search_query=ultimate+frisbee+for+kids+camp+beginner+rules"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: Endzone Ultimate-Lite","url":"https://www.google.com/search?q=ultimate+frisbee+lite+kids+camp+rules"}],"variations":["Foam-ball swap keeps the passing game alive when no disc or no thrower has the knack for a frisbee yet.","Three-pass rule requires at least three completions before a team may score, forcing patient teamwork over one long heave.","Self-officiated stall-ten for grades 10-12 adds the full Ultimate stall count and player-made foul calls, building real game IQ.","Mini-court 4-on-4 shrinks the field for smaller groups so everyone touches the disc every point."],"subsets":[["Make the endzones generous (10+ feet deep) so catches near the line are clearly in or out."],["Demo a pull so the throwing team learns to give the other side a fair start."],["Count '1-2-3-4-5' aloud over a volunteer holder so everyone hears the stall."],["Practice a give-and-go cut at walking pace before the live point."],[],[]]},
  {"id":"og-human-foosball-grid","title":"Human Foosball","altNames":["Living Foosball","Chalk-Grid Foosball","Rope-Line Soccer"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":12,"groupMax":22,"energy":3,"prep":"Medium","blurb":"A life-sized foosball table — players locked to chalk lanes can only slide side to side as the ball flies through.","materials":["Sidewalk chalk to draw the lane grid","1 playground ball (lightweight, low-bounce)","4 cones for two goals","2 sets of team identifiers"],"materialTags":["Sidewalk chalk","Playground balls","Cones","Team identifiers"],"steps":["Chalk a large rectangle and draw straight lanes across it like the rods of a foosball table, alternating which team's row sits in each lane.","Assign players to lanes so each row mixes both teams the way real foosball rods alternate; everyone must keep at least one foot on their own line.","Drop the ball at center; players slide along their lane to kick it but may never step out of their lane.","The ball passes between lanes as players boot it toward the far goal; no one chases up or down the field.","Reset to center after every goal and after the ball leaves the grid.","First team to a goal total wins, then rotate players to fresh lanes so everyone plays different positions."],"notes":"Chalking the grid is the main prep; pre-draw it before campers arrive so you go straight into play. The one-foot-on-the-line rule is the whole game — assign a counselor to watch for 'lane jumpers'. For grades 10-12, narrow the lanes, add a true goalkeeper lane, and forbid the ball from being stopped (it must be played first-touch), which forces fast reads and real positional teamwork.","safety":"Players stay in their own lane, which naturally prevents collisions — enforce it strictly. Use a soft, lightweight ball and ban high kicks above the knee since players stand close together.","ages":["g46","g79","g1012"],"rating":5,"media":[{"title":"Video demos: Human Foosball","url":"https://www.youtube.com/results?search_query=human+foosball+camp+game+chalk+grid+setup"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Human Foosball","url":"https://www.google.com/search?q=human+foosball+how+to+set+up+camp"}],"variations":["Rope lanes instead of chalk let you set up on grass where chalk won't show; lay parallel jump ropes as the rods.","Two-ball mode drops a second ball in to double the chaos and force players to track both threats.","Pro lanes for grades 10-12 narrow every row and add a first-touch-only rule so no one can trap and dribble.","Hands-version uses a foam ball thrown and batted instead of kicked, ideal when a field is uneven for soccer."],"subsets":[["Draw lanes wide enough (about 6 feet) that a sliding player still has room.","Alternate lane colors or labels so teams find their rows fast."],["Walk one player down their lane to show the 'one foot always on the line' limit."],[],[],[],[]]},
  {"id":"og-predator-prey-chain","title":"Predator & Prey Food Chain","altNames":["Food Chain Tag","Ecosystem Tag","Predator Prey Game"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":12,"groupMax":30,"energy":3,"prep":"Medium","blurb":"A living food chain on the field — rabbits, foxes, and hawks chase what they eat and flee what eats them.","materials":["3 colors of team identifiers or armbands (rabbits, foxes, hawks)","20-30 'food' tokens such as beanbags or paper scraps scattered as grass","6 cones for boundaries and a safe burrow"],"materialTags":["Team identifiers","Beanbag","Cones"],"steps":["Assign roles by color: most campers are rabbits, fewer are foxes, fewest are hawks; scatter food tokens across the field as 'grass'.","Rabbits collect three food tokens to survive a round, but foxes hunt rabbits and hawks hunt foxes — a tag means you're eaten.","An eaten player doesn't leave; they hand their identifier to the predator who tagged them and respawn as that predator's species.","Mark a small 'burrow' cone-zone where any prey is safe for a slow ten-count, but no eating happens there either.","Run timed rounds of about three minutes; between rounds count how many of each species survived and discuss why.","Replay with the new species balance and watch the populations swing like a real ecosystem."],"notes":"This doubles as a nature/STEM lesson — the respawn-as-predator rule makes population balance visible and gives a real talking point afterward. Set the starting ratio roughly 6 rabbits : 3 foxes : 1 hawk. For grades 7-9, add energy rules (a fox that doesn't eat within a round 'starves' and becomes a rabbit) so campers reason about carrying capacity and balance.","safety":"Tags are open-hand touches; the burrow safe zone gives tired or overwhelmed players a breather, so keep it clearly marked. Scatter food tokens away from the hard-charging chase lanes so no one trips diving for grass.","ages":["g46","g79"],"rating":4,"media":[{"title":"Video demos: Predator Prey Food Chain","url":"https://www.youtube.com/results?search_query=predator+prey+food+chain+ecosystem+tag+game+camp"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: Predator Prey Food Chain","url":"https://www.google.com/search?q=predator+prey+food+chain+tag+game+ecosystem+lesson"}],"variations":["Drought round removes half the food tokens to show how scarcity crashes the rabbit population first.","Four-tier chain adds 'grass-eater, mouse, snake, hawk' for older campers to model a longer chain and more interactions.","Starvation rule for grades 7-9 demotes any predator that fails to eat in a round, teaching carrying capacity through play.","Disease card secretly marks a few prey as 'sick'; a predator that eats them is slowed for ten seconds, adding risk to hunting."],"subsets":[["Use clearly different colors so a player can read at a glance who eats them and who they eat."],["Post a simple chain poster (rabbit → fox → hawk) at the burrow for quick reference."],["Demo the hand-off respawn so an 'eaten' player knows exactly what to do."],[],["Tally on a clipboard so the population swing is visible to discuss."],[]]},
  {"id":"og-four-corners-elimination","title":"Four Corners Standoff","altNames":["Four Corners","Corner Gamble","Pick-a-Corner"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":10,"groupMax":30,"energy":2,"prep":"Low","blurb":"Dash to a corner before the blindfolded caller picks one to wipe out — pure nerve and gamble.","materials":["4 cones to mark numbered corners","1 blindfold or just instruct the caller to close eyes","Sidewalk chalk to number corners 1-4"],"materialTags":["Cones","Sidewalk chalk"],"steps":["Number four corners 1 through 4 and pick one camper to be the caller, who closes their eyes in the center.","While the caller counts to ten aloud, everyone quietly walks to any corner they choose.","At 'ten' the caller (eyes still shut) calls one number; everyone in that corner is out and sits down.","The caller opens their eyes, the survivors scatter again, and a new count begins.","Keep eliminating until only a few campers remain in the open field; the last camper standing becomes the next caller.","Speed up the counts as the group shrinks to ramp the tension."],"notes":"It's a low-energy reset game — great after a hard-running block or to settle a hyped group. The strategy is reading the caller's habits and committing late. For grades 7-9, add a 'split decision' where the caller may name two corners at once, or a 'safe-once' token each player can spend to survive a hit, layering risk management onto the gamble.","safety":"Keep the walk to corners a brisk walk, not a sprint, to avoid pile-ups at the cones. Make sure corners are well clear of fences and the field surface is even since players watch the caller, not the ground.","ages":["g46","g79"],"rating":3,"media":[{"title":"Video demos: Four Corners Standoff","url":"https://www.youtube.com/results?search_query=four+corners+elimination+game+camp+how+to+play"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Four Corners Standoff","url":"https://www.google.com/search?q=four+corners+game+rules+variations"}],"variations":["Double-call lets the caller name two corners at once late in the game, halving the survivors fast for older groups.","Save token gives each player one one-time pass to survive being called, adding a resource-management gamble for grades 7-9.","Team corners splits the group into pairs who must stay together, so a call wipes both and choices carry double weight.","Silent-walk-only rule disqualifies anyone the caller hears moving, rewarding stealth over speed."],"subsets":[["Chalk big bold numbers so players can pick a corner from across the field."],["Stress that movement stops the instant the caller hits 'ten'."],[],[],[],[]]},
  {"id":"og-tv-freeze-tag","title":"TV Freeze Tag","altNames":["TV Tag","Channel Tag","Freeze TV Tag"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":8,"groupMax":24,"energy":3,"prep":"None","blurb":"Freeze tag with a catch — to unfreeze, you have to drop and shout a TV show, and no show can be used twice.","materials":["4-6 cones to mark a boundary"],"materialTags":["Cones"],"steps":["Cone off a play area and pick one or two taggers; everyone else scatters inside.","A tagged player freezes in a wide stance with feet apart.","To unfreeze yourself, drop to a squat and shout the name of a TV show — but you may not repeat any show already called that round.","If you can't think of a new show before a tagger reaches you, you stay frozen and become a tagger's helper.","When too many players are frozen and out of shows, end the round; the last unfrozen player starts the next round as tagger.","Swap the category between rounds — movies, snacks, animals — to keep the recall fresh."],"notes":"The no-repeats memory rule is what makes this harder and funnier than plain freeze tag; it gets harder as the round goes on and shows run out. For grades 7-9, raise the bar with a tighter category (only shows starting with a chosen letter, or naming a character too), and add 'crawl to revive' where a free player must crawl under a frozen teammate's legs to thaw them, mixing strategy with movement.","safety":"Frozen players stand still in a stable stance, not on one foot, to avoid wobbling falls. Keep taggers from blindsiding squatting players — approach from the front so no one collides with a crouched camper.","ages":["g46","g79"],"rating":3,"media":[{"title":"Video demos: TV Freeze Tag","url":"https://www.youtube.com/results?search_query=tv+tag+freeze+tag+camp+game+rules"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: TV Freeze Tag","url":"https://www.google.com/search?q=tv+tag+freeze+tag+variations+camp"}],"variations":["Crawl-to-thaw requires a free teammate to crawl under a frozen player's legs to unfreeze them, adding a rescue mechanic.","Letter-locked category for grades 7-9 forces every called show to start with a chosen letter, sharply raising the difficulty.","Category roulette has a counselor flip the theme mid-round (shows to sports to foods), testing quick mental gear-shifts.","Two-helper cap limits how many taggers the frozen can become, keeping the runners from getting overwhelmed too fast."],"subsets":[[],["Demo the wide-stance freeze so a thaw-crawl variation works cleanly later."],["Pick the category aloud first so no one freezes blank on the first tag."],[],[],[]]},
  {"id":"og-medley-relay-circuit","title":"Medley Relay Circuit","altNames":["Crazy Relay","Station Relay Race","Medley Relay"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":12,"groupMax":24,"energy":3,"prep":"Medium","blurb":"A relay where every leg is a different silly challenge — crab-walk, balloon-carry, hula-hoop spin, and sprint home.","materials":["8 cones to mark lanes and turnarounds","2 balloons per team","2 hula hoops per team","2 playground balls per team","1 baton per team (a rolled paper tube works)"],"materialTags":["Cones","Balloons","Hula hoops","Playground balls"],"steps":["Split into even teams and line each up behind a start cone with a turnaround cone out in front.","Assign each leg a different movement: leg one crab-walks, leg two carries a balloon between their knees, leg three hula-hoops to the cone and back, leg four sprints.","On 'go' the first runner does their movement out to the cone and back, then hands the baton to the next.","If a balloon drops or a hoop falls, the runner stops and fixes it before continuing — no skipping the challenge.","The whole team must complete every leg in order; first team with all runners home and seated wins.","Reshuffle who runs which leg and race again so everyone tries the hard ones."],"notes":"Set the stations before campers arrive and demo each movement once so the relay flows without stoppages. The mix of skills means the fastest team isn't always the most coordinated, keeping it fair. For grades 10-12, lengthen the course, add a mental leg (solve a riddle at the cone before turning back), and require a clean baton exchange behind a line or the leg re-runs, adding precision pressure.","safety":"Crab-walkers move backward, so keep generous space between lanes and a clear turnaround. Pop and clear any burst balloon scraps immediately since pieces are a slip and choking hazard.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Video demos: Medley Relay Circuit","url":"https://www.youtube.com/results?search_query=crazy+relay+race+stations+camp+field+day"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Medley Relay Circuit","url":"https://www.google.com/search?q=medley+relay+race+challenge+stations+camp"}],"variations":["Surprise-leg version hides the next movement in a sealed card the runner flips at the line, adding a thinking-on-your-feet twist.","Pairs relay sends two campers per leg who must complete the challenge linked at the elbow, doubling the coordination.","Brain-and-body for grades 10-12 adds a riddle or math card at the turnaround that must be solved before sprinting back.","Backwards day reverses every movement (sprint becomes a slow walk, crab-walk becomes a bear-crawl) to refresh a repeat group."],"subsets":[["Mark a clear baton-exchange box so hand-offs don't bunch up at the line."],["Demo each of the four movements once so no runner is confused mid-race.","Match harder legs to a mix of abilities, not all to the fastest kids."],[],[],[],[]]},
  {"id":"og-ninja-warrior-course","title":"Ninja Warrior Field Course","altNames":["Ninja Warrior Course","Obstacle Gauntlet","Field Ninja Run"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":60,"groupMin":8,"groupMax":20,"energy":3,"prep":"High","blurb":"Build a timed gauntlet of crawl-tunnels, hoop-hops, balance lines, and a final dash from pure camp supplies.","materials":["10-12 cones for slalom and markers","5 hula hoops for a hop grid","Jump ropes or chalk for balance lines","Cardboard boxes for a crawl tunnel","Masking tape for floor targets","1 stopwatch or phone timer","Playground balls for a knock-target station"],"materialTags":["Cones","Hula hoops","Yarn","Cardboard","Masking tape","Playground balls"],"steps":["Lay out 5-6 stations in a loop: a cone slalom, a hula-hoop hop grid, a balance line on chalk or rope, a cardboard crawl tunnel, a ball-throw target, and a sprint to the buzzer cone.","Walk the whole group through each station once, demonstrating exactly what 'completed' looks like.","Send campers one at a time and run the stopwatch; a missed hoop or stepped-off balance line means redo that station.","Post each camper's time on a board so they can chase a personal best on a second run.","After everyone's first run, let campers re-attempt to beat their time while others cheer.","Tear down and rebuild a harder layout if time allows, or run it as a head-to-head bracket for the finale."],"notes":"Setup is the big lift — pre-build the course and have a second counselor staff the far stations to enforce 'redo' calls. The personal-best chase keeps slower campers motivated since they race the clock, not each other. For grades 10-12, add penalty seconds for faults instead of redos, a memory station (repeat a sequence shown at the start), and a head-to-head dual-lane finale for real competition.","safety":"Inspect the crawl tunnel and balance line so nothing can collapse or roll; keep tunnels short and open at both ends. Station spotters at the balance and hop elements, and keep a clear run-out past the final sprint cone so no one crashes into a fence.","ages":["g46","g79","g1012"],"rating":5,"media":[{"title":"Video demos: Ninja Warrior Field Course","url":"https://www.youtube.com/results?search_query=ninja+warrior+obstacle+course+camp+diy+kids"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Ninja Warrior Field Course","url":"https://www.google.com/search?q=diy+ninja+warrior+obstacle+course+camp+kids"}],"variations":["Team relay mode sends one camper per station so a squad passes a baton through the gauntlet, rewarding the whole team's weakest link.","Mystery-station adds a card flip at one cone that assigns a surprise mini-challenge, keeping repeat runs fresh.","Penalty-second scoring for grades 10-12 replaces redos with added time per fault, so speed and accuracy trade off strategically.","Memory finale shows a four-move sequence at the start that must be performed correctly at the last station to stop the clock."],"subsets":[["Sketch the loop on paper first so stations flow without backtracking.","Space stations far enough apart that a running camper never reaches the next while one is mid-attempt."],["Show the exact pass/fail standard for each station so 'redo' calls aren't arguments."],["Have a spotter call faults at the balance and hop grids."],[],[],[]]},
  {"id":"og-dragon-tail-chase","title":"Dragon Tail Chase","altNames":["Dragon Tail","Catch the Dragon's Tail","Snake Tail Tag"],"type":"Game","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":10,"groupMax":20,"energy":3,"prep":"Low","blurb":"A human dragon chases its own tail — the head tries to grab the flag tucked in the very last player's belt.","materials":["1 cloth flag or bandana per dragon to be the 'tail'","6 cones to mark a boundary"],"materialTags":["Flags or pinnies","Cones"],"steps":["Line up 8-10 campers single file, each holding the shoulders of the person ahead, to form a dragon.","Tuck a bandana into the back waistband of the very last player — that's the tail.","On 'go' the front player (the head) tries to reach back and snatch the tail while the whole line stays connected.","The body twists and whips to protect the tail; if the line breaks apart, it must stop and re-link before continuing.","When the head grabs the tail, that head goes to the back and becomes the new tail; everyone shifts up one spot.","With a big group, run two dragons side by side that may also try to steal each other's tails."],"notes":"The catch is that the head and tail are the same dragon, so it's a coordination puzzle as much as a chase. Coach the body to move as one unit. For grades 7-9, run two competing dragons in a shared space so each must protect its own tail while raiding the other's, turning it into a frantic team-vs-team strategy game.","safety":"Keep grips on shoulders, never around necks or waists, and ban whip-cracking yanks that could snap the back players off their feet. Drop hands and stop instantly if anyone falls so the line doesn't pile on.","ages":["g46","g79"],"rating":4,"media":[{"title":"Video demos: Dragon Tail Chase","url":"https://www.youtube.com/results?search_query=catch+the+dragon+tail+game+camp+kids"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: Dragon Tail Chase","url":"https://www.google.com/search?q=catch+the+dragons+tail+game+rules"}],"variations":["Two-dragon battle for grades 7-9 pits rival lines in one zone, each guarding its tail while hunting the other's.","Three-tail dragon tucks flags at three spots along a long line, so the head must capture all three before resetting.","Silent-dragon rule bans the head from calling directions, forcing the body to read movement and self-coordinate.","Short-dragon sprint version uses lines of just four for smaller groups, making the chase faster and tighter."],"subsets":[["Keep dragons to about 10 players; longer lines whip dangerously and snap apart constantly."],["Tuck the flag loosely so it pulls free easily and no one tugs at a player."],[],["Demo a controlled re-link so a broken line knows to pause, not collide."],[],[]]},
  {"id":"og-flag-football-lite","title":"Flag Football-Lite","altNames":["Flag Football","No-Tackle Football","Belt-Pull Football"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":10,"groupMax":16,"energy":3,"prep":"Low","blurb":"Football without the tackles — pull the flag from the ball-carrier's belt to stop the drive.","materials":["2 flags or bandanas per player tucked at each hip","1 playground ball or foam football","8 cones for endzones, sidelines, and the line of scrimmage","2 sets of team identifiers"],"materialTags":["Flags or pinnies","Playground balls","Cones","Team identifiers"],"steps":["Cone a field with two endzones and tuck two flags into each player's waistband at the hips.","Split into two teams; the offense gets four downs to move the ball into the opponent's endzone for a score.","Each down starts at the line of scrimmage; the quarterback hands off or throws, and the carrier runs.","A defender stops the play by pulling a flag from the carrier's belt — no tackling, grabbing, or blocking with the body.","If the offense fails to score in four downs, the ball turns over to the other team at that spot.","Score a touchdown by carrying or catching the ball in the endzone; most touchdowns in the time cap wins."],"notes":"Keep teams small (5-on-5 or fewer) so everyone touches the ball and the field doesn't clog. Rotate the quarterback every series so it isn't one camper's show. For grades 10-12, add real downs-and-yardage with first-down lines, a count for the rush ('five-Mississippi' before crossing the line), and designed plays drawn in the huddle, sneaking in genuine strategy and teamwork.","safety":"Strictly no contact — flags are pulled, never the player; ban diving for flags and screen-blocking with arms or shoulders. Make sure flags pull free easily so no one yanks a camper off balance, and keep cones clear of the sideline fence.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Video demos: Flag Football-Lite","url":"https://www.youtube.com/results?search_query=flag+football+for+kids+camp+beginner+rules"}],"links":[{"label":"S&S Blog: top summer camp themes and activity ideas","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"},{"label":"More ideas: Flag Football-Lite","url":"https://www.google.com/search?q=flag+football+lite+kids+camp+rules"}],"variations":["Everyone-eligible rule lets any offensive player catch a pass, so even small teams run wide-open passing games.","Two-hand-touch swap replaces belt flags with a two-hand touch when you have no flags on hand.","Playbook huddle for grades 10-12 requires each down's play to be drawn in the huddle and a defensive coverage called, building real game IQ.","Continuous-motion version allows the quarterback to run after a five-count, forcing defenses to balance rush and coverage."],"subsets":[["Tuck flags at the hip with most of the flag hanging free so pulls are clean."],["Keep sides to five or fewer so every camper gets touches."],[],["Demo a clean flag pull and the no-contact standard before live play."],[],[]]},
  {"id":"og-british-bulldog-gentle","title":"Gentle British Bulldog","altNames":["British Bulldog","Bulldog","Bullrush"],"type":"Game","place":"Outside","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":12,"groupMax":30,"energy":3,"prep":"Low","blurb":"Charge from wall to wall past the bulldogs in the middle — a two-hand touch sends you to join the pack.","materials":["8 cones to mark two safe lines about 40 feet apart","Optional pinnies to mark the bulldogs"],"materialTags":["Cones","Team identifiers"],"steps":["Mark two safe lines about 40 feet apart and pick one or two 'bulldogs' to stand in the middle zone.","Everyone else lines up safe behind one line as the 'runners'.","On the bulldog's call of 'Bulldog!', all runners must dash to the opposite safe line.","Bulldogs catch runners with a clear two-hand touch on the back or shoulders — no tackling, lifting, or grabbing clothes.","A caught runner becomes a bulldog and joins the middle for the next charge.","Keep calling charges until one runner remains; that survivor becomes the first bulldog next game."],"notes":"The 'gentle' framing matters — this game is banned in some places for contact, so enforce two-hand-touch-only from the first charge and it stays safe and great. The strategy is timing your run and using the crowd as cover. For grades 10-12, narrow the field so dodging is harder, add a rule that the last few runners must charge solo, and let bulldogs coordinate a pincer, raising the tactical stakes.","safety":"Two-hand touches only on the back or shoulders — absolutely no tackling, bear-hugging, or pulling on clothing, which is how this game gets people hurt. Run on flat grass clear of obstacles, keep all runners moving the same direction each charge, and forbid diving.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Video demos: Gentle British Bulldog","url":"https://www.youtube.com/results?search_query=british+bulldog+game+rules+two+hand+touch+camp"}],"links":[{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"More ideas: Gentle British Bulldog","url":"https://www.google.com/search?q=british+bulldog+game+safe+rules+camp"}],"variations":["Flag-pull bulldog replaces touches with pulling a tucked flag, removing contact entirely for the most cautious groups.","Treasure-charge has runners grab a beanbag from the far line and carry it back, adding an objective to the dash.","Narrow-gauntlet for grades 10-12 shrinks the running zone so runners must juke a coordinated bulldog pincer.","Solo-charge endgame makes the final runners cross one at a time, turning the last rounds into pure 1-versus-many strategy."],"subsets":[["Set lines 40 feet apart on flat grass with a clear run-out behind each."],[],[],["Demo the exact two-hand touch standard and have a counselor watch for grabbing on every charge."],[],[]]},
];
